function getDepth(path) {
  if (!path || path === "-") return 0;
  return path.split("/").filter(Boolean).length;
}

function isGroup(e) {
  return ["G", "CG", "Raiz"].includes(e);
}

function typeLabel(t) {
  if (t === "N") return "Numérico";
  if (t === "C") return "Alfanum.";
  if (t === "D") return "Data";
  if (t === "-") return "Grupo";
  return t;
}

function occurLabel(o) {
  if (o === "1-1") return "Obrigatório";
  if (o === "0-1") return "Opcional";
  if (o === "-") return "—";
  return o;
}

