  redLight: "#450a0a",
  yellow: "#facc15",
  yellowLight: "#422006",
  badge: "#334155",
  badgeText: "#94a3b8",
  panelBg: "#1e293b",
  tableHead: "#0f172a",
  tableRowHover: "#2d3748",
