// ─── App ──────────────────────────────────────────────────────────────────────

const TABS = [
  { id: "layout", label: "Leiaute", icon: "◻" },
  { id: "servicos", label: "Serviços", icon: "⬡" },
  { id: "nbs", label: "NBS", icon: "◈" },
  { id: "erros", label: "Erros", icon: "⚠" },
];

export default function App() {
  const [tab, setTab] = useState("layout");
  const [search, setSearch] = useState("");
  const [selectedItem, setSelectedItem] = useState(null);
  const [selectedField, setSelectedField] = useState(null);
  const [filterObrig, setFilterObrig] = useState("all");
  const [expandedGroups, setExpandedGroups] = useState(new Set());
  const [darkMode, setDarkMode] = useState(false);
  const searchRef = useRef(null);
  const T = darkMode ? DARK : LIGHT;

  // Reset search on tab change
  useEffect(() => {
    setSearch("");
    setSelectedField(null);
    setSelectedItem(null);
    setExpandedGroups(new Set());
  }, [tab]);

  // Keyboard shortcut: / to focus search, Escape to close panel
  useEffect(() => {
    const handler = (e) => {
      if (e.key === "/" && document.activeElement !== searchRef.current) {
        e.preventDefault();
        searchRef.current?.focus();
      }
      if (e.key === "Escape") {
        setSelectedField(null);
        setSelectedItem(null);
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  // ── Layout filtering ─────────────────────────────────────────────────────────
  const filteredLayout = useMemo(() => {
    const q = search.toLowerCase().trim();
    return RAW_LAYOUT.filter((x) => {
      const matchSearch = !q || x.f.toLowerCase().includes(q) || x.d.toLowerCase().includes(q) || x.p.toLowerCase().includes(q);
      const matchFilter = filterObrig === "all" || (filterObrig === "obrig" && x.o === "1-1") || (filterObrig === "opc" && x.o === "0-1");
      return matchSearch && matchFilter;
    });
  }, [search, filterObrig]);

  // ── Services filtering ───────────────────────────────────────────────────────
  const filteredServices = useMemo(() => {
    const q = search.toLowerCase().trim();
    if (!q) return SERVICES_DATA;
    const result = {};
    Object.entries(SERVICES_DATA).forEach(([k, v]) => {
      const matchLabel = v.label.toLowerCase().includes(q);
      const filteredSvcs = v.svcs.filter(svc =>
        svc.c.includes(q) || svc.d.toLowerCase().includes(q) || svc.subLabel.toLowerCase().includes(q)
      );
      if (matchLabel || filteredSvcs.length > 0) {
        result[k] = { ...v, svcs: matchLabel ? v.svcs : filteredSvcs };
      }
    });
    return result;
  }, [search]);

  const totalSvcMatches = useMemo(() => {
    return Object.values(filteredServices).reduce((acc, v) => acc + v.svcs.length, 0);
  }, [filteredServices]);

  const totalSvcs = useMemo(() => {
    return Object.values(SERVICES_DATA).reduce((acc, v) => acc + v.svcs.length, 0);
  }, []);

  // ── NBS filtering ────────────────────────────────────────────────────────────
  const filteredNbs = useMemo(() => {
    const q = search.toLowerCase().trim();
    if (!q) return NBS_DATA;
    return NBS_DATA.filter(n => n.c.toLowerCase().includes(q) || n.d.toLowerCase().includes(q));
  }, [search]);

  // ── Errors filtering ─────────────────────────────────────────────────────────
  const filteredErrors = useMemo(() => {
    const q = search.toLowerCase().trim();
    return ERRORS_DATA.filter((e) => {
      return !q || e.c.toLowerCase().includes(q) || e.m.toLowerCase().includes(q) || e.f.toLowerCase().includes(q) || e.p.toLowerCase().includes(q);
    });
  }, [search]);

  // ── Styles ───────────────────────────────────────────────────────────────────
  const styles = {
    root: {
      minHeight: "100vh",
      background: T.bg,
      color: T.text,
      fontFamily: "'JetBrains Mono', 'Fira Mono', 'Cascadia Code', 'Consolas', monospace",
      fontSize: "13px",
      transition: "background 0.2s, color 0.2s",
    },
    header: {
      background: T.surface,
      borderBottom: `1px solid ${T.border}`,
      padding: "0 24px",
      display: "flex",
      alignItems: "center",
      gap: "24px",
      height: "56px",
      boxShadow: T.shadow,
      position: "sticky",
      top: 0,
      zIndex: 100,
    },
    logo: {
      fontSize: "15px",
      fontWeight: 700,
      color: T.accent,
      letterSpacing: "-0.3px",
      whiteSpace: "nowrap",
    },
    tabs: {
      display: "flex",
      gap: "2px",
      flex: 1,
    },
    tab: (active) => ({
      padding: "6px 14px",
      borderRadius: "6px",
      border: "none",
      background: active ? T.accentLight : "transparent",
      color: active ? T.accent : T.textSecondary,
      fontWeight: active ? 600 : 400,
      fontSize: "13px",
      cursor: "pointer",
      transition: "all 0.15s",
      display: "flex",
      alignItems: "center",
      gap: "6px",
    }),
    searchBar: {
      display: "flex",
      alignItems: "center",
      gap: "8px",
      background: T.bg,
      border: `1px solid ${T.border}`,
      borderRadius: "8px",
      padding: "6px 12px",
      minWidth: "220px",
      transition: "border-color 0.15s",
    },
    searchInput: {
      border: "none",
      background: "transparent",
      color: T.text,
      fontSize: "13px",
      outline: "none",
      width: "100%",
    },
    themeBtn: {
      background: T.badge,
      border: `1px solid ${T.border}`,
      borderRadius: "8px",
      padding: "6px 10px",
      cursor: "pointer",
      color: T.textSecondary,
      fontSize: "16px",
      display: "flex",
      alignItems: "center",
      transition: "all 0.15s",
    },
    main: {
      display: "flex",
      height: "calc(100vh - 56px)",
      overflow: "hidden",
    },
    list: {
      flex: 1,
      overflow: "auto",
      padding: "0",
    },
    // Scrollable panel overlay
    panel: {
      width: "420px",
      minWidth: "380px",
      background: T.panelBg,
      borderLeft: `1px solid ${T.border}`,
      display: "flex",
      flexDirection: "column",
      overflow: "hidden",
      boxShadow: `-4px 0 20px rgba(0,0,0,${darkMode ? '0.3' : '0.06'})`,
    },
    panelHeader: {
      padding: "16px 20px",
      borderBottom: `1px solid ${T.border}`,
      background: T.surface,
      flexShrink: 0,
    },
    panelScroll: {
      flex: 1,
      overflowY: "auto",
      padding: "20px",
    },
  };

  // ── Render tabs ───────────────────────────────────────────────────────────────
  return (
    <div style={styles.root}>
      <header style={styles.header}>
        <div style={styles.logo}>NFS-e Referência</div>

        <nav style={styles.tabs}>
          {TABS.map((t) => (
            <button
              key={t.id}
              style={styles.tab(tab === t.id)}
              onClick={() => setTab(t.id)}
            >
              <span>{t.icon}</span>
              {t.label}
            </button>
          ))}
        </nav>

        <div style={styles.searchBar}>
          <span style={{ color: T.textMuted, fontSize: "12px", userSelect: "none" }}>⌕</span>
          <input
            ref={searchRef}
            style={styles.searchInput}
            placeholder={
              tab === "layout" ? "Campo, caminho, descrição…" :
              tab === "servicos" ? "Código ou descrição…" :
              tab === "nbs" ? "Código NBS ou descrição…" :
              "Código, campo, mensagem…"
            }
            value={search}
            onChange={(e) => { setSearch(e.target.value); setSelectedField(null); setSelectedItem(null); }}
          />
          {search && (
            <button onClick={() => setSearch("")} style={{ background: "none", border: "none", cursor: "pointer", color: T.textMuted, fontSize: "14px", padding: 0 }}>✕</button>
          )}
        </div>

        <button style={styles.themeBtn} onClick={() => setDarkMode(d => !d)} title="Alternar tema">
          {darkMode ? "☀️" : "🌙"}
        </button>
      </header>

      <div style={styles.main}>
        {tab === "layout" && (
          <LayoutTab
            T={T}
            filteredLayout={filteredLayout}
            selectedField={selectedField}
            setSelectedField={setSelectedField}
            filterObrig={filterObrig}
            setFilterObrig={setFilterObrig}
            expandedGroups={expandedGroups}
            setExpandedGroups={setExpandedGroups}
            styles={styles}
          />
        )}
        {tab === "servicos" && (
          <ServicesTab
            T={T}
            filteredServices={filteredServices}
            totalSvcMatches={totalSvcMatches}
            totalSvcs={totalSvcs}
            selectedItem={selectedItem}
            setSelectedItem={setSelectedItem}
            search={search}
            styles={styles}
          />
        )}
        {tab === "nbs" && (
          <NbsTab
            T={T}
            filteredNbs={filteredNbs}
            selectedItem={selectedItem}
            setSelectedItem={setSelectedItem}
            search={search}
            styles={styles}
          />
        )}
        {tab === "erros" && (
          <ErrorsTab
            T={T}
            filteredErrors={filteredErrors}
            selectedField={selectedField}
            setSelectedField={setSelectedField}
            styles={styles}
          />
        )}
      </div>

      <footer style={{
        borderTop: `1px solid ${T.border}`,
        background: T.surface,
        padding: "10px 24px",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        fontSize: "11px",
        color: T.textMuted,
        flexShrink: 0,
      }}>
        <span>NFS-e Sistema Nacional · Leiaute v1.01 · Anexo I SEFIN ADN DPS · 2026</span>
        <a
          href="https://www.gov.br/nfse/pt-br/biblioteca/documentacao-tecnica/documentacao-atual"
          target="_blank"
          rel="noopener noreferrer"
          style={{ color: T.accent, textDecoration: "none", fontWeight: 500 }}
        >
          Documentação Oficial ↗
        </a>
      </footer>
    </div>
  );
}

// ─── Layout Tab ───────────────────────────────────────────────────────────────

function LayoutTab({ T, filteredLayout, selectedField, setSelectedField, filterObrig, setFilterObrig, expandedGroups, setExpandedGroups, styles }) {
  const colW = ["28%", "8%", "9%", "9%", "46%"];

  const toggleGroup = (key) => {
    setExpandedGroups(prev => {
      const next = new Set(prev);
      next.has(key) ? next.delete(key) : next.add(key);
      return next;
    });
  };

  return (
    <>
      <div style={{ ...styles.list, background: T.bg }}>
        {/* Toolbar */}
        <div style={{
          padding: "12px 16px",
          borderBottom: `1px solid ${T.border}`,
          background: T.surface,
          display: "flex",
          alignItems: "center",
          gap: "8px",
          position: "sticky",
          top: 0,
          zIndex: 10,
        }}>
          <span style={{ color: T.textMuted, fontSize: "11px", marginRight: "4px" }}>Filtro:</span>
          {[["all", "Todos"], ["obrig", "Obrigatórios"], ["opc", "Opcionais"]].map(([v, l]) => (
            <button key={v} onClick={() => setFilterObrig(v)} style={{
              padding: "4px 10px",
              borderRadius: "5px",
              border: `1px solid ${filterObrig === v ? T.accent : T.border}`,
              background: filterObrig === v ? T.accentLight : "transparent",
              color: filterObrig === v ? T.accent : T.textSecondary,
              fontSize: "11px",
              cursor: "pointer",
              fontWeight: filterObrig === v ? 600 : 400,
            }}>{l}</button>
          ))}
          <span style={{ marginLeft: "auto", color: T.textMuted, fontSize: "11px" }}>
            {filteredLayout.length} campo{filteredLayout.length !== 1 ? "s" : ""}
          </span>
        </div>

        {/* Table header */}
        <div style={{
          display: "grid",
          gridTemplateColumns: colW.join(" "),
          background: T.tableHead,
          borderBottom: `2px solid ${T.border}`,
          padding: "0 16px",
          position: "sticky",
          top: "45px",
          zIndex: 9,
        }}>
          {["Campo", "Tipo", "Ocorrência", "Tamanho", "Descrição"].map((h, i) => (
            <div key={h} style={{
              padding: "8px 6px",
              color: T.textMuted,
              fontSize: "11px",
              fontWeight: 600,
              textTransform: "uppercase",
              letterSpacing: "0.5px",
              textAlign: i === 2 || i === 3 ? "center" : "left",
            }}>{h}</div>
          ))}
        </div>

        {/* Rows */}
        {filteredLayout.map((row, idx) => {
          const depth = getDepth(row.p);
          const group = isGroup(row.e);
          const groupKey = row.p + row.f;
          const isExpanded = expandedGroups.has(groupKey);

          return (
            <div
              key={idx}
              onClick={() => {
                if (group) toggleGroup(groupKey);
                setSelectedField(row);
              }}
              style={{
                display: "grid",
                gridTemplateColumns: colW.join(" "),
                padding: "0 16px",
                borderBottom: `1px solid ${T.border}`,
                background: selectedField === row
                  ? T.tableRowSelected
                  : idx % 2 === 0 ? T.surface : T.bg,
                cursor: "pointer",
                transition: "background 0.1s",
              }}
              onMouseEnter={e => { if (selectedField !== row) e.currentTarget.style.background = T.tableRowHover; }}
              onMouseLeave={e => {
                if (selectedField !== row) {
                  e.currentTarget.style.background = idx % 2 === 0 ? T.surface : T.bg;
                }
              }}
            >
              {/* Field name */}
              <div style={{ padding: "8px 6px", display: "flex", alignItems: "center", gap: "4px" }}>
                <span style={{ display: "inline-block", width: `${depth * 14}px`, flexShrink: 0 }} />
                {group && (
                  <span style={{ color: T.textMuted, fontSize: "10px", marginRight: "2px" }}>
                    {isExpanded ? "▾" : "▸"}
                  </span>
                )}
                <span style={{
                  fontFamily: "monospace",
                  fontSize: "12px",
                  fontWeight: group ? 600 : 400,
                  color: group ? T.accent : T.text,
                  wordBreak: "break-all",
                }}>{row.f}</span>
                {row.e === "ID" && (
                  <span style={{
                    marginLeft: "4px",
                    background: T.accentMid,
                    color: darkModeCheck(T) ? "#fff" : T.accent,
                    fontSize: "9px",
                    padding: "1px 4px",
                    borderRadius: "3px",
                    fontWeight: 700,
                  }}>ID</span>
                )}
                {row.e === "CE" && (
                  <span style={{
                    marginLeft: "4px",
                    background: T.badge,
                    color: T.textMuted,
                    fontSize: "9px",
                    padding: "1px 4px",
                    borderRadius: "3px",
                  }}>CE</span>
                )}
              </div>

              {/* Type */}
              <div style={{ padding: "8px 6px", color: T.textMuted, fontSize: "11px" }}>
                {!group && typeLabel(row.t)}
              </div>

              {/* Occurrence */}
              <div style={{ padding: "8px 6px", textAlign: "center" }}>
                {!group && (
                  <span style={{
                    fontSize: "10px",
                    padding: "2px 6px",
                    borderRadius: "4px",
                    fontWeight: 500,
                    background: row.o === "1-1" ? T.greenLight : T.badge,
                    color: row.o === "1-1" ? T.green : T.textMuted,
                  }}>
                    {occurLabel(row.o)}
                  </span>
                )}
              </div>

              {/* Size */}
              <div style={{ padding: "8px 6px", textAlign: "center", color: T.textMuted, fontSize: "11px", fontFamily: "monospace" }}>
                {!group && row.s !== "-" && row.s}
              </div>

              {/* Description */}
              <div style={{ padding: "8px 6px", color: T.textSecondary, fontSize: "12px", overflow: "hidden" }}>
                <span style={{ display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>
                  {row.d}
                </span>
              </div>
            </div>
          );
        })}
      </div>

      {/* Detail panel */}
      {selectedField && (
        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div>
                <div style={{ fontFamily: "monospace", fontSize: "16px", fontWeight: 700, color: T.accent }}>
                  {selectedField.f}
                </div>
                <div style={{ color: T.textMuted, fontSize: "11px", marginTop: "2px" }}>
                  {selectedField.p || "—"}
                </div>
              </div>
              <button onClick={() => setSelectedField(null)} style={{
                background: T.badge,
                border: "none",
                borderRadius: "6px",
                padding: "4px 10px",
                cursor: "pointer",
                color: T.textSecondary,
                fontSize: "13px",
              }}>✕</button>
            </div>
          </div>
          <div style={styles.panelScroll}>
            <DetailGrid T={T} items={[
              ["Elemento", selectedField.e],
              ["Tipo", typeLabel(selectedField.t)],
              ["Ocorrência", occurLabel(selectedField.o)],
              ["Tamanho", selectedField.s],
              ["Caminho completo", selectedField.p + selectedField.f],
            ]} />
            {selectedField.d && (
              <FieldBlock T={T} label="Descrição">{selectedField.d}</FieldBlock>
            )}
            {selectedField.n && (
              <FieldBlock T={T} label="Observações" accent>{selectedField.n}</FieldBlock>
            )}
          </div>
        </div>
      )}
    </>
  );
}

// ─── Services Tab ─────────────────────────────────────────────────────────────

function ServicesTab({ T, filteredServices, totalSvcMatches, totalSvcs, selectedItem, setSelectedItem, search, styles }) {
  const entries = Object.entries(filteredServices);
  const isSearching = !!search.trim();

  // Track which item groups are expanded (by item key)
  const [expandedItems, setExpandedItems] = useState(new Set());

  const toggleItem = (k) => {
    setExpandedItems(prev => {
      const next = new Set(prev);
      next.has(k) ? next.delete(k) : next.add(k);
      return next;
    });
  };

  return (
    <>
      <div style={{ ...styles.list, background: T.bg }}>
        <div style={{
          padding: "12px 16px",
          borderBottom: `1px solid ${T.border}`,
          background: T.surface,
          display: "flex",
          alignItems: "center",
          gap: "8px",
          position: "sticky",
          top: 0,
          zIndex: 10,
        }}>
          <span style={{ color: T.textMuted, fontSize: "11px" }}>
            {isSearching
              ? `${totalSvcMatches} resultado${totalSvcMatches !== 1 ? "s" : ""} em ${entries.length} grupo${entries.length !== 1 ? "s" : ""}`
              : `${totalSvcs} serviços · ${entries.length} itens`
            }
          </span>
        </div>

        {entries.map(([k, v]) => {
          const isOpen = isSearching || expandedItems.has(k);
          return (
            <div key={k}>
              {/* Group header — clickable to collapse/expand */}
              <div
                onClick={() => !isSearching && toggleItem(k)}
                style={{
                  padding: "10px 16px",
                  background: T.tableHead,
                  borderBottom: `1px solid ${T.border}`,
                  borderTop: `1px solid ${T.border}`,
                  display: "flex",
                  alignItems: "center",
                  gap: "10px",
                  cursor: isSearching ? "default" : "pointer",
                  userSelect: "none",
                  transition: "background 0.1s",
                }}
                onMouseEnter={e => { if (!isSearching) e.currentTarget.style.background = T.tableRowHover; }}
                onMouseLeave={e => { if (!isSearching) e.currentTarget.style.background = T.tableHead; }}
              >
                {!isSearching && (
                  <span style={{ color: T.textMuted, fontSize: "10px", width: "12px", flexShrink: 0 }}>
                    {isOpen ? "▾" : "▸"}
                  </span>
                )}
                <span style={{
                  background: T.accentLight,
                  color: T.accent,
                  fontWeight: 700,
                  fontSize: "11px",
                  padding: "2px 8px",
                  borderRadius: "5px",
                  flexShrink: 0,
                }}>Item {k}</span>
                <span style={{ fontWeight: 600, color: T.text, fontSize: "12px", flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{v.label}</span>
                <span style={{
                  marginLeft: "auto",
                  background: T.badge,
                  color: T.textMuted,
                  fontSize: "10px",
                  padding: "2px 7px",
                  borderRadius: "10px",
                  flexShrink: 0,
                }}>{v.svcs.length}</span>
              </div>

              {/* Services — only visible when expanded or searching */}
              {isOpen && v.svcs.map((svc, i) => (
                <div
                  key={svc.c}
                  onClick={() => setSelectedItem({ type: "svc", item: k, itemLabel: v.label, svc })}
                  style={{
                    display: "flex",
                    alignItems: "flex-start",
                    gap: "12px",
                    padding: "9px 16px 9px 28px",
                    borderBottom: `1px solid ${T.border}`,
                    background: (selectedItem?.svc?.c === svc.c)
                      ? T.tableRowSelected
                      : i % 2 === 0 ? T.surface : T.bg,
                    cursor: "pointer",
                    transition: "background 0.1s",
                  }}
                  onMouseEnter={e => { if (selectedItem?.svc?.c !== svc.c) e.currentTarget.style.background = T.tableRowHover; }}
                  onMouseLeave={e => { if (selectedItem?.svc?.c !== svc.c) e.currentTarget.style.background = i % 2 === 0 ? T.surface : T.bg; }}
                >
                  <span style={{
                    fontSize: "12px",
                    fontWeight: 700,
                    color: T.accent,
                    flexShrink: 0,
                    paddingTop: "1px",
                    minWidth: "52px",
                  }}>{svc.c}</span>
                  <div style={{ flex: 1 }}>
                    <div style={{ color: T.text, fontSize: "12px", lineHeight: 1.5 }}>{svc.d}</div>
                    {svc.subLabel && svc.subLabel !== svc.d && (
                      <div style={{ color: T.textMuted, fontSize: "11px", marginTop: "2px" }}>
                        Sub {svc.sub}: {svc.subLabel}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          );
        })}

        {entries.length === 0 && (
          <div style={{ padding: "60px 24px", textAlign: "center", color: T.textMuted }}>
            Nenhum resultado encontrado para "{search}"
          </div>
        )}
      </div>

      {selectedItem?.type === "svc" && (
        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div>
                <div style={{ fontFamily: "monospace", fontSize: "18px", fontWeight: 700, color: T.accent }}>
                  {selectedItem.svc.c}
                </div>
                <div style={{ color: T.textMuted, fontSize: "11px", marginTop: "2px" }}>
                  Código de Tributação Nacional
                </div>
              </div>
              <button onClick={() => setSelectedItem(null)} style={{
                background: T.badge,
                border: "none",
                borderRadius: "6px",
                padding: "4px 10px",
                cursor: "pointer",
                color: T.textSecondary,
                fontSize: "13px",
              }}>✕</button>
            </div>
          </div>
          <div style={styles.panelScroll}>
            <FieldBlock T={T} label="Descrição">{selectedItem.svc.d}</FieldBlock>
            <DetailGrid T={T} items={[
              ["Item", selectedItem.item + " — " + selectedItem.itemLabel],
              ["Subitem", selectedItem.svc.sub + (selectedItem.svc.subLabel ? " — " + selectedItem.svc.subLabel : "")],
              ["Código", selectedItem.svc.c],
            ]} />
            <div style={{ marginTop: "16px", padding: "12px", background: T.accentLight, borderRadius: "8px", fontSize: "11px", color: T.textSecondary }}>
              <strong style={{ color: T.accent }}>Formato cTribNac:</strong>
              <br />
              IISSPNN — Item(2) + Subitem(2) + Desdobro(2) + Seq(2)
            </div>
          </div>
        </div>
      )}
    </>
  );
}

// ─── NBS Tab ──────────────────────────────────────────────────────────────────

function NbsTab({ T, filteredNbs, selectedItem, setSelectedItem, search, styles }) {
  const isSearching = !!search.trim();

  // Build tree: chapter → positions → subpositions
  const tree = useMemo(() => {
    const chapters = [];
    let currentChapter = null;
    let currentPosition = null;

    NBS_DATA.forEach(item => {
      if (item.level === "chapter") {
        currentChapter = { ...item, positions: [] };
        currentPosition = null;
        chapters.push(currentChapter);
      } else if (item.level === "position") {
        currentPosition = { ...item, subs: [] };
        if (currentChapter) currentChapter.positions.push(currentPosition);
      } else {
        if (currentPosition) currentPosition.subs.push(item);
        else if (currentChapter) {
          // subposition without a position parent — attach as orphan
          currentChapter.positions.push({ ...item, subs: [] });
        }
      }
    });
    return chapters;
  }, []);

  // Expanded state: sets of chapter codes and position codes
  const [expandedChapters, setExpandedChapters] = useState(new Set());
  const [expandedPositions, setExpandedPositions] = useState(new Set());

  const toggleChapter = (c) => setExpandedChapters(prev => {
    const next = new Set(prev); next.has(c) ? next.delete(c) : next.add(c); return next;
  });
  const togglePosition = (c) => setExpandedPositions(prev => {
    const next = new Set(prev); next.has(c) ? next.delete(c) : next.add(c); return next;
  });

  // When searching, filter tree and show matching items flat-ish
  const visibleTree = useMemo(() => {
    if (!isSearching) return tree;
    const q = search.toLowerCase().trim();
    return tree
      .map(ch => {
        const chMatch = ch.c.toLowerCase().includes(q) || ch.d.toLowerCase().includes(q);
        const filteredPositions = ch.positions
          .map(pos => {
            const posMatch = pos.c.toLowerCase().includes(q) || pos.d.toLowerCase().includes(q);
            const filteredSubs = pos.subs.filter(s => s.c.toLowerCase().includes(q) || s.d.toLowerCase().includes(q));
            if (posMatch || filteredSubs.length > 0) return { ...pos, subs: posMatch ? pos.subs : filteredSubs, _open: true };
            return null;
          })
          .filter(Boolean);
        if (chMatch || filteredPositions.length > 0) return { ...ch, positions: chMatch ? ch.positions.map(p => ({ ...p, _open: true })) : filteredPositions, _open: true };
        return null;
      })
      .filter(Boolean);
  }, [isSearching, search, tree]);

  const totalVisible = isSearching
    ? filteredNbs.length
    : NBS_DATA.length;

  return (
    <>
      <div style={{ ...styles.list, background: T.bg }}>
        <div style={{
          padding: "12px 16px",
          borderBottom: `1px solid ${T.border}`,
          background: T.surface,
          display: "flex",
          alignItems: "center",
          gap: "8px",
          position: "sticky",
          top: 0,
          zIndex: 10,
        }}>
          <span style={{ color: T.textMuted, fontSize: "11px" }}>
            {isSearching
              ? `${totalVisible} resultado${totalVisible !== 1 ? "s" : ""}`
              : `${NBS_DATA.length} itens · ${tree.length} capítulos`}
          </span>
        </div>

        {visibleTree.map((ch) => {
          const chOpen = isSearching ? ch._open : expandedChapters.has(ch.c);
          return (
            <div key={ch.c}>
              {/* Chapter row */}
              <div
                onClick={() => { if (!isSearching) toggleChapter(ch.c); setSelectedItem({ type: "nbs", item: ch }); }}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: "10px",
                  padding: "10px 16px",
                  borderBottom: `1px solid ${T.border}`,
                  borderTop: `1px solid ${T.border}`,
                  background: selectedItem?.item?.c === ch.c ? T.tableRowSelected : T.tableHead,
                  cursor: "pointer",
                  transition: "background 0.1s",
                  userSelect: "none",
                }}
                onMouseEnter={e => { if (selectedItem?.item?.c !== ch.c) e.currentTarget.style.background = T.tableRowHover; }}
                onMouseLeave={e => { if (selectedItem?.item?.c !== ch.c) e.currentTarget.style.background = T.tableHead; }}
              >
                {!isSearching && (
                  <span style={{ color: T.textMuted, fontSize: "10px", width: "12px", flexShrink: 0 }}>
                    {chOpen ? "▾" : "▸"}
                  </span>
                )}
                <span style={{ fontSize: "11px", fontWeight: 700, color: T.accent, flexShrink: 0, minWidth: "72px" }}>{ch.c}</span>
                <div style={{ flex: 1, fontWeight: 600, color: T.text, fontSize: "12px", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{ch.d}</div>
                <span style={{ background: T.accentLight, color: T.accent, fontSize: "9px", padding: "2px 6px", borderRadius: "4px", fontWeight: 700, flexShrink: 0 }}>CAP</span>
              </div>

              {/* Positions */}
              {chOpen && ch.positions.map((pos) => {
                const posOpen = isSearching ? pos._open : expandedPositions.has(pos.c);
                return (
                  <div key={pos.c}>
                    {/* Position row */}
                    <div
                      onClick={() => { if (!isSearching) togglePosition(pos.c); setSelectedItem({ type: "nbs", item: pos }); }}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: "10px",
                        padding: "8px 16px 8px 28px",
                        borderBottom: `1px solid ${T.border}`,
                        background: selectedItem?.item?.c === pos.c ? T.tableRowSelected : T.surface,
                        cursor: "pointer",
                        transition: "background 0.1s",
                        userSelect: "none",
                      }}
                      onMouseEnter={e => { if (selectedItem?.item?.c !== pos.c) e.currentTarget.style.background = T.tableRowHover; }}
                      onMouseLeave={e => { if (selectedItem?.item?.c !== pos.c) e.currentTarget.style.background = T.surface; }}
                    >
                      {!isSearching && pos.subs.length > 0 && (
                        <span style={{ color: T.textMuted, fontSize: "10px", width: "12px", flexShrink: 0 }}>
                          {posOpen ? "▾" : "▸"}
                        </span>
                      )}
                      {(!(!isSearching && pos.subs.length > 0)) && <span style={{ width: "12px", flexShrink: 0 }} />}
                      <span style={{ fontSize: "11px", fontWeight: 600, color: T.textSecondary, flexShrink: 0, minWidth: "72px" }}>{pos.c}</span>
                      <div style={{ flex: 1, color: T.textSecondary, fontSize: "12px" }}>{pos.d}</div>
                    </div>

                    {/* Subpositions */}
                    {posOpen && pos.subs.map((sub, si) => (
                      <div
                        key={sub.c}
                        onClick={() => setSelectedItem({ type: "nbs", item: sub })}
                        style={{
                          display: "flex",
                          alignItems: "flex-start",
                          gap: "10px",
                          padding: "7px 16px 7px 52px",
                          borderBottom: `1px solid ${T.border}`,
                          background: selectedItem?.item?.c === sub.c ? T.tableRowSelected : si % 2 === 0 ? T.bg : T.surface,
                          cursor: "pointer",
                          transition: "background 0.1s",
                        }}
                        onMouseEnter={e => { if (selectedItem?.item?.c !== sub.c) e.currentTarget.style.background = T.tableRowHover; }}
                        onMouseLeave={e => { if (selectedItem?.item?.c !== sub.c) e.currentTarget.style.background = si % 2 === 0 ? T.bg : T.surface; }}
                      >
                        <span style={{ fontSize: "10px", fontWeight: 500, color: T.textMuted, flexShrink: 0, minWidth: "72px", paddingTop: "1px" }}>{sub.c}</span>
                        <div style={{ flex: 1, color: T.textMuted, fontSize: "11px", lineHeight: 1.5 }}>{sub.d}</div>
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          );
        })}

        {visibleTree.length === 0 && (
          <div style={{ padding: "60px 24px", textAlign: "center", color: T.textMuted }}>
            Nenhum resultado encontrado para "{search}"
          </div>
        )}
      </div>

      {selectedItem?.type === "nbs" && (
        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div>
                <div style={{ fontFamily: "monospace", fontSize: "16px", fontWeight: 700, color: T.accent }}>
                  {selectedItem.item.c}
                </div>
                <div style={{ color: T.textMuted, fontSize: "11px", marginTop: "2px" }}>
                  Nomenclatura Brasileira de Serviços
                </div>
              </div>
              <button onClick={() => setSelectedItem(null)} style={{
                background: T.badge,
                border: "none",
                borderRadius: "6px",
                padding: "4px 10px",
                cursor: "pointer",
                color: T.textSecondary,
                fontSize: "13px",
              }}>✕</button>
            </div>
          </div>
          <div style={styles.panelScroll}>
            <FieldBlock T={T} label="Descrição">{selectedItem.item.d}</FieldBlock>
            <DetailGrid T={T} items={[
              ["Código NBS", selectedItem.item.c],
              ["Nível", selectedItem.item.level === "chapter" ? "Capítulo" : selectedItem.item.level === "position" ? "Posição" : "Subposição"],
            ]} />
            <div style={{ marginTop: "16px", padding: "12px", background: T.accentLight, borderRadius: "8px", fontSize: "11px", color: T.textSecondary }}>
              <strong style={{ color: T.accent }}>Campo cNBS na DPS:</strong>
              <br />
              Código de 9 dígitos. Obrigatório em exportação/importação e operações IBS/CBS.
            </div>
          </div>
        </div>
      )}
    </>
  );
}

// ─── Errors Tab ───────────────────────────────────────────────────────────────

function ErrorsTab({ T, filteredErrors, selectedField, setSelectedField, styles }) {
  const effectColor = (ef) => {
    if (!ef) return { bg: T.badge, text: T.textMuted };
    if (ef.includes("Rej")) return { bg: T.redLight, text: T.red };
    if (ef.includes("Obrig")) return { bg: T.orangeLight, text: T.orange };
    return { bg: T.badge, text: T.textMuted };
  };

  return (
    <>
      <div style={{ ...styles.list, background: T.bg }}>
        <div style={{
          padding: "12px 16px",
          borderBottom: `1px solid ${T.border}`,
          background: T.surface,
          position: "sticky",
          top: 0,
          zIndex: 10,
        }}>
          <span style={{ color: T.textMuted, fontSize: "11px" }}>
            {filteredErrors.length} erro{filteredErrors.length !== 1 ? "s" : ""}
          </span>
        </div>

        {filteredErrors.map((err, idx) => {
          const ec = effectColor(err.ef);
          return (
            <div
              key={err.c + idx}
              onClick={() => setSelectedField(err)}
              style={{
                display: "flex",
                alignItems: "flex-start",
                gap: "12px",
                padding: "10px 16px",
                borderBottom: `1px solid ${T.border}`,
                background: selectedField === err
                  ? T.tableRowSelected
                  : idx % 2 === 0 ? T.surface : T.bg,
                cursor: "pointer",
                transition: "background 0.1s",
              }}
              onMouseEnter={e => { if (selectedField !== err) e.currentTarget.style.background = T.tableRowHover; }}
              onMouseLeave={e => { if (selectedField !== err) e.currentTarget.style.background = idx % 2 === 0 ? T.surface : T.bg; }}
            >
              <div style={{ flexShrink: 0, paddingTop: "1px" }}>
                <div style={{
                  fontFamily: "monospace",
                  fontWeight: 700,
                  fontSize: "12px",
                  color: T.accent,
                }}>{err.c}</div>
                <div style={{
                  marginTop: "4px",
                  fontSize: "10px",
                  background: ec.bg,
                  color: ec.text,
                  padding: "1px 5px",
                  borderRadius: "3px",
                  textAlign: "center",
                  fontWeight: 600,
                }}>{err.ef || "—"}</div>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ color: T.text, fontSize: "12px", lineHeight: 1.5 }}>{err.m}</div>
                <div style={{ color: T.textMuted, fontSize: "11px", marginTop: "4px", fontFamily: "monospace" }}>
                  {err.p}<strong style={{ color: T.textSecondary }}>{err.f}</strong>
                </div>
              </div>
            </div>
          );
        })}

        {filteredErrors.length === 0 && (
          <div style={{ padding: "60px 24px", textAlign: "center", color: T.textMuted }}>
            Nenhum resultado encontrado.
          </div>
        )}
      </div>

      {selectedField && selectedField.c && (
        <div style={styles.panel}>
          <div style={styles.panelHeader}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div>
                <div style={{ fontFamily: "monospace", fontSize: "18px", fontWeight: 700, color: T.accent }}>
                  {selectedField.c}
                </div>
                <div style={{ color: T.textMuted, fontSize: "11px", marginTop: "2px" }}>
                  {selectedField.ef} · Nível {selectedField.l}
                </div>
              </div>
              <button onClick={() => setSelectedField(null)} style={{
                background: T.badge,
                border: "none",
                borderRadius: "6px",
                padding: "4px 10px",
                cursor: "pointer",
                color: T.textSecondary,
                fontSize: "13px",
              }}>✕</button>
            </div>
          </div>
          <div style={styles.panelScroll}>
            <FieldBlock T={T} label="Mensagem">{selectedField.m}</FieldBlock>
            {selectedField.r && (
              <FieldBlock T={T} label="Resolução" accent>{selectedField.r}</FieldBlock>
            )}
            {selectedField.o && (
              <FieldBlock T={T} label="Observações">{selectedField.o}</FieldBlock>
            )}
            <DetailGrid T={T} items={[
              ["Campo", selectedField.f],
              ["Caminho", selectedField.p],
              ["Nível", selectedField.l],
              ["Efeito", selectedField.ef],
            ]} />
          </div>
        </div>
      )}
    </>
  );
}

// ─── Shared sub-components ────────────────────────────────────────────────────

function DetailGrid({ T, items }) {
  return (
    <div style={{ display: "grid", gridTemplateColumns: "auto 1fr", gap: "6px 12px", marginBottom: "16px" }}>
      {items.map(([label, value]) => value && value !== "—" ? (
        <>
          <div key={label + "l"} style={{ color: T.textMuted, fontSize: "11px", paddingTop: "2px", whiteSpace: "nowrap" }}>{label}</div>
          <div key={label + "v"} style={{ color: T.text, fontSize: "12px", fontFamily: label === "Campo" || label === "Código" || label === "Código NBS" ? "monospace" : "inherit", wordBreak: "break-all" }}>{value}</div>
        </>
      ) : null)}
    </div>
  );
}

function FieldBlock({ T, label, children, accent }) {
  return (
    <div style={{ marginBottom: "16px" }}>
      <div style={{ fontSize: "10px", fontWeight: 700, textTransform: "uppercase", letterSpacing: "0.8px", color: T.textMuted, marginBottom: "6px" }}>{label}</div>
      <div style={{
        background: accent ? T.accentLight : T.tableHead,
        border: `1px solid ${accent ? T.accentMid : T.border}`,
        borderRadius: "8px",
        padding: "12px",
        fontSize: "12px",
        lineHeight: 1.7,
        color: T.textSecondary,
        whiteSpace: "pre-wrap",
        wordBreak: "break-word",
      }}>{children}</div>
    </div>
  );
}

function darkModeCheck(T) {
  return T.bg === "#0f172a";
}
